SELECT 'requests' as tableName, COUNT(*) as count FROM requests
UNION ALL
SELECT 'approvalInstances', COUNT(*) FROM approvalInstances
UNION ALL
SELECT 'approvalTasks', COUNT(*) FROM approvalTasks
UNION ALL
SELECT 'approvalHistory', COUNT(*) FROM approvalHistory;

